import{c as t,Q as a,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const b=JSON.parse('{"title":"Browser Use and Computer Use","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/browser-computer-use.md","filePath":"getting-started/browser-computer-use.md","lastUpdated":1778736656000}'),r={name:"getting-started/browser-computer-use.md"};function n(i,e,d,p,l,c){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="browser-use-and-computer-use" tabindex="-1">Browser Use and Computer Use <a class="header-anchor" href="#browser-use-and-computer-use" aria-label="Permalink to &quot;Browser Use and Computer Use&quot;">​</a></h1><p>Memoh can give a bot a visible workspace desktop and a headed browser inside its workspace container. This is different from running a headless Playwright script: the bot can inspect and operate the same graphical browser that you can see in the Web UI display pane.</p><h2 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Capability</th><th>Best for</th><th>How it works</th></tr></thead><tbody><tr><td>Headless browser commands</td><td>Fast scripted automation inside a workspace</td><td>Run Playwright or other browser tooling as normal workspace commands.</td></tr><tr><td>Browser Use</td><td>Web pages, forms, navigation, screenshots, accessibility-tree inspection</td><td>Operates the headed workspace Chrome/Chromium instance over CDP.</td></tr><tr><td>Computer Use</td><td>Native dialogs, broken browser state, non-browser GUI, coordinate-level recovery</td><td>Uses desktop screenshots plus pointer and keyboard input.</td></tr></tbody></table><p>Prefer Browser Use for web pages. Use Computer Use when the task depends on GUI state that CDP cannot reach.</p><h2 id="workspace-display-and-vnc" tabindex="-1">Workspace display and VNC <a class="header-anchor" href="#workspace-display-and-vnc" aria-label="Permalink to &quot;Workspace display and VNC&quot;">​</a></h2><p>Workspace display is the desktop environment inside the bot&#39;s workspace container. VNC/RFB is the display and input transport behind that desktop, while WebRTC is used by the Web UI display session.</p><p>The main value is not VNC by itself. The important capability is that the workspace can run a headed Chrome/Chromium browser for sites and login flows that do not work well in headless mode.</p><h2 id="preparing-a-bot-desktop" tabindex="-1">Preparing a bot desktop <a class="header-anchor" href="#preparing-a-bot-desktop" aria-label="Permalink to &quot;Preparing a bot desktop&quot;">​</a></h2><ol><li>Open the bot detail page.</li><li>Go to the <strong>Desktop</strong> tab.</li><li>Prepare or enable the workspace display runtime.</li><li>Open a display session from the bot settings page or from the chat workspace.</li></ol><p>The display runtime installs or uses the workspace desktop, VNC server, browser, and fonts needed for the visible session. Availability depends on the workspace backend and image.</p><h2 id="agent-tools" tabindex="-1">Agent tools <a class="header-anchor" href="#agent-tools" aria-label="Permalink to &quot;Agent tools&quot;">​</a></h2><p>When workspace desktop is enabled, the agent can use browser and computer tools:</p><ul><li><code>browser_observe</code> inspects the current browser page.</li><li><code>browser_action</code> clicks, fills, types, presses, and navigates in the headed browser.</li><li><code>browser_remote_session</code> exposes the browser CDP endpoint for code-driven sessions.</li><li><code>computer_use</code> takes screenshots and sends pointer or keyboard input to the desktop.</li></ul><p>These tools are workspace runtime features. They do not automate the Electron desktop app itself.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/getting-started/container.html">Bot Workspace Management</a></li><li><a href="/installation/workspace-backends.html">Workspace Backends</a></li></ul>',17)])])}const u=t(r,[["render",n]]);export{b as __pageData,u as default};
